import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

/**
 * Detect and report the usage of the old ktlint-disable / ktlint-enable directives.
 * These directives are deprecated and should be replaced with @Suppress annotations.
 */
public class KtlintSuppressionRule : Rule(
    ruleId = KTLINT_SUPPRESSION_RULE_ID,
    about =
        About(
            maintainer = "KtLint",
            repositoryUrl = "https://github.com/pinterest/ktlint",
            issueTrackerUrl = "https://github.com/pinterest/ktlint/issues",
        ),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> visitEolComment(node, emit)
            BLOCK_COMMENT -> visitBlockComment(node, emit)
        }
    }

    private fun visitEolComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("//")
                .trim()
        if (text.startsWith(KTLINT_DISABLE_DIRECTIVE)) {
            emit(
                node.startOffset,
                "Directive '$KTLINT_DISABLE_DIRECTIVE' in EOL comment is deprecated. Replace with @Suppress annotation",
                false,
            )
        }
    }

    private fun visitBlockComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        when {
            text.startsWith(KTLINT_DISABLE_DIRECTIVE) -> {
                emit(
                    node.startOffset,
                    "Directive '$KTLINT_DISABLE_DIRECTIVE' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                )
            }
            text.startsWith(KTLINT_ENABLE_DIRECTIVE) -> {
                emit(
                    node.startOffset,
                    "Directive '$KTLINT_ENABLE_DIRECTIVE' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                )
            }
        }
    }

    private companion object {
        const val KTLINT_DISABLE_DIRECTIVE = "ktlint-disable"
        const val KTLINT_ENABLE_DIRECTIVE = "ktlint-enable"
    }
}

/**
 * The rule id for the internal rule that detects the usage of the deprecated ktlint-disable and ktlint-enable directives.
 * This rule is internal and will always run, even when suppressed via @Suppress annotations or ktlint-disable directives.
 */
public val KTLINT_SUPPRESSION_RULE_ID: RuleId = RuleId("standard:ktlint-suppression")
"}

{"file_path": "/project/ktlint-rule-engine/src/main/kotlin/com/pinterest/ktlint/rule/engine/internal/rulefilter/InternalRuleProvidersFilter.kt", "content": "package com.pinterest.ktlint.rule.engine.internal.rulefilter

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.internal.rules.KtlintSuppressionRule
import com.pinterest.ktlint.rule.engine.internal.rules.KTLINT_SUPPRESSION_RULE_ID

/**
 * Adds the internal rule providers to the set of rule providers. Internal rules are always executed.
 */
internal class InternalRuleProvidersFilter : RuleFilter {
    override fun filter(ruleProviders: Set<RuleProvider>): Set<RuleProvider> =
        ruleProviders +
            // Add internal rules that are always executed
            INTERNAL_RULE_PROVIDERS.filter { internalRuleProvider ->
                // Only add if not already present (to avoid duplicates)
                ruleProviders.none { it.ruleId == internalRuleProvider.ruleId }
            }

    private companion object {
        val INTERNAL_RULE_PROVIDERS =
            setOf(
                RuleProvider { KtlintSuppressionRule() },
            )
    }
}

/**
 * Checks whether the given rule id belongs to an internal rule that cannot be suppressed.
 */
internal fun isInternalRuleId(ruleId: com.pinterest.ktlint.rule.engine.core.api.RuleId): Boolean =
    ruleId == KTLINT_SUPPRESSION_RULE_ID
"}

