import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.api.LintError
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class KtlintSuppressionRuleTest {
    @Nested
    inner class `Given an EOL comment with ktlint-disable` {
        @Test
        fun `Given an EOL comment with ktlint-disable directive then report a lint error`() {
            val code =
                """
                val foo = "foo" // ktlint-disable
                """.trimIndent()
            assertThat(lint(code)).contains(
                LintError(
                    1,
                    17,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }

        @Test
        fun `Given an EOL comment with ktlint-disable directive for specific rules then report a lint error`() {
            val code =
                """
                val foo = "foo" // ktlint-disable some-rule-id other-rule-id
                """.trimIndent()
            assertThat(lint(code)).contains(
                LintError(
                    1,
                    17,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }
    }

    @Nested
    inner class `Given a block comment with ktlint-disable or ktlint-enable` {
        @Test
        fun `Given a block comment with ktlint-disable directive then report a lint error`() {
            val code =
                """
                /* ktlint-disable */
                val foo = "foo"
                /* ktlint-enable */
                """.trimIndent()
            val lintErrors = lint(code)
            assertThat(lintErrors).contains(
                LintError(
                    1,
                    1,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
            assertThat(lintErrors).contains(
                LintError(
                    3,
                    1,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-enable' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }

        @Test
        fun `Given a block comment with ktlint-disable directive for specific rules then report a lint error`() {
            val code =
                """
                /* ktlint-disable some-rule-id other-rule-id */
                val foo = "foo"
                /* ktlint-enable some-rule-id other-rule-id */
                """.trimIndent()
            val lintErrors = lint(code)
            assertThat(lintErrors).contains(
                LintError(
                    1,
                    1,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
            assertThat(lintErrors).contains(
                LintError(
                    3,
                    1,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-enable' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }
    }

    @Nested
    inner class `Given that the ktlint-suppression rule cannot be suppressed` {
        @Test
        fun `Given an EOL comment with ktlint-disable directive which tries to suppress the ktlint-suppression rule then still report a lint error`() {
            val code =
                """
                val foo = "foo" // ktlint-disable ktlint-suppression
                """.trimIndent()
            assertThat(lint(code)).contains(
                LintError(
                    1,
                    17,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }

        @Test
        fun `Given a Suppress annotation for all ktlint rules then still report a lint error for ktlint-disable directive`() {
            val code =
                """
                @file:Suppress("ktlint")

                val foo = "foo" // ktlint-disable
                """.trimIndent()
            assertThat(lint(code)).contains(
                LintError(
                    3,
                    17,
                    KTLINT_SUPPRESSION_RULE_ID,
                    "Directive 'ktlint-disable' in EOL comment is deprecated. Replace with @Suppress annotation",
                    false,
                ),
            )
        }
    }

    @Nested
    inner class `Given a comment that is not a suppression directive` {
        @Test
        fun `Given a regular EOL comment then do not report a lint error`() {
            val code =
                """
                val foo = "foo" // Some regular comment
                """.trimIndent()
            assertThat(lint(code)).noneMatch { it.ruleId == KTLINT_SUPPRESSION_RULE_ID }
        }

        @Test
        fun `Given a regular block comment then do not report a lint error`() {
            val code =
                """
                /* Some regular comment */
                val foo = "foo"
                """.trimIndent()
            assertThat(lint(code)).noneMatch { it.ruleId == KTLINT_SUPPRESSION_RULE_ID }
        }
    }

    private fun lint(code: String) =
        ArrayList<LintError>().apply {
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { KtlintSuppressionRule() },
                    ),
            ).lint(Code.fromSnippet(code)) { e -> add(e) }
        }
}
"}

