{"file_path": "/project/ktlint-ruleset-standard/src/main/kotlin/com/pinterest/ktlint/ruleset/standard/rules/KtlintSuppressionRule.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

/**
 * Detect and report the usage of the deprecated ktlint-disable / ktlint-enable directives.
 * These directives are deprecated and should be replaced with @Suppress annotations.
 *
 * This rule cannot be suppressed via @Suppress annotation or ktlint-disable directives.
 */
public class KtlintSuppressionRule : StandardRule("ktlint-suppression") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> visitEolComment(node, emit)
            BLOCK_COMMENT -> visitBlockComment(node, emit)
        }
    }

    private fun visitEolComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("//")
                .trim()
        if (text.startsWith(KTLINT_DISABLE_DIRECTIVE)) {
            emit(
                node.startOffset,
                "Directive '$KTLINT_DISABLE_DIRECTIVE' in EOL comment is deprecated. Replace with @Suppress annotation",
                false,
            )
        }
    }

    private fun visitBlockComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        when {
            text.startsWith(KTLINT_DISABLE_DIRECTIVE) -> {
                emit(
                    node.startOffset,
                    "Directive '$KTLINT_DISABLE_DIRECTIVE' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                )
            }
            text.startsWith(KTLINT_ENABLE_DIRECTIVE) -> {
                emit(
                    node.startOffset,
                    "Directive '$KTLINT_ENABLE_DIRECTIVE' in block comment is deprecated. Replace with @Suppress annotation",
                    false,
                )
            }
        }
    }

    private companion object {
        const val KTLINT_DISABLE_DIRECTIVE = "ktlint-disable"
        const val KTLINT_ENABLE_DIRECTIVE = "ktlint-enable"
    }
}

/**
 * The rule id for the rule that detects the usage of the deprecated ktlint-disable and ktlint-enable directives.
 * This rule cannot be suppressed via @Suppress annotations or ktlint-disable directives.
 */
public val KTLINT_SUPPRESSION_RULE_ID: RuleId = KtlintSuppressionRule().ruleId
"}

