            }
        val autoCorrect = this.autoCorrect && !suppress
        val emit =
            if (suppress) {
                SUPPRESS_EMIT
            } else {
                this.emit
            }
        function(autoCorrect, emit)
    }

    private companion object {
        // Swallow violation so that it is not emitted
        val SUPPRESS_EMIT: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit = { _, _, _ -> }

        // The rule ID of the ktlint-suppression rule. This is hardcoded to avoid a circular dependency between
        // ktlint-rule-engine and ktlint-ruleset-standard modules.
        const val KTLINT_SUPPRESSION_RULE_ID = "standard:ktlint-suppression"
    }
}"}

